import{_ as t,o as i,c as a,ae as n}from"./chunks/framework.BvHJbMD4.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"core-1/802.11-technologies.md","filePath":"core-1/802.11-technologies.md"}'),r={name:"core-1/802.11-technologies.md"};function o(d,e,l,s,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="terms" tabindex="-1">TERMS <a class="header-anchor" href="#terms" aria-label="Permalink to &quot;TERMS&quot;">​</a></h2><p>Bandwidth - The amount of spectrum that we would use for that communication. Bluetooth - Connects devices to eachother and exchange data IEEE - Institue of Electrical &amp; Electronics Engieers ISM - Industrial, Scientific and Medical Band</p><table tabindex="0"><thead><tr><th>TERM</th><th>DEFINITION</th><th>DESCRIPTION</th></tr></thead><tbody><tr><td>Bandwidth</td><td>The amount of spectrum that we would use for that communication.</td><td>???</td></tr><tr><td>Bluetooth</td><td>Connects devices to eachother and exchange data.</td><td>Uses 2.4 GHz range. Referred to as the unlicensed ISM frequencies. Maximum range of 10 meters (30 feet). Often uses NFC in conjustion with your moblie phone to be able to give it the configuration params it needs to connect to your network.</td></tr><tr><td>IEEE</td><td>WiFi 7</td><td>Institue of Electrical &amp; Electronics Engieers</td></tr><tr><td>ISM</td><td>Industrial, Scientific and Medical Band</td><td>???</td></tr><tr><td>RFID</td><td>Radio Frequency Identification</td><td>About the size of a grain of rice. Can have batteries or not. Batteries allow for longer distance scanning, without batteries the scanner usually powers it. Can be used inside key cards for building access, products of the assembly lines or be put inside your pets which allows them to be scanned and know immediatley who the pet belongs to</td></tr><tr><td>NFC</td><td>Near-Field Communication</td><td>Builds on RFID technology making 2-way communication instead of 1. Commonly used on your phone/smart watch to pay for products.</td></tr><tr><td>ISM</td><td>WiFi ??</td><td>???</td></tr></tbody></table><h2 id="_802-11-technologies" tabindex="-1">802.11 Technologies <a class="header-anchor" href="#_802-11-technologies" aria-label="Permalink to &quot;802.11 Technologies&quot;">​</a></h2><ul><li>Institue of Electrical &amp; Electronics Engineers</li><li>802.11 Committe</li><li>Everyone follows these standards</li><li>WiFi version will increment accordingly</li></ul><table tabindex="0"><thead><tr><th>Name</th><th>Wifi</th></tr></thead><tbody><tr><td>802.11ac</td><td>WiFi 5</td></tr><tr><td>802.11ax</td><td>WiFi 6 &amp; WiFi 6E (Extended)</td></tr><tr><td>802.11be</td><td>WiFi 7</td></tr><tr><td>802.11??</td><td>WiFi ??</td></tr></tbody></table><h3 id="frequencies" tabindex="-1">Frequencies <a class="header-anchor" href="#frequencies" aria-label="Permalink to &quot;Frequencies&quot;">​</a></h3><ul><li>2.4 ghz</li><li>5 ghz</li><li>6 ghz</li><li>Sometimes it&#39;s a combination Channels</li><li>groups of frequencies, numbered by IEEE</li><li>Frequencies are managed by goerning entities</li><li>using non-overlapping channels would be optimal Bandwidth</li><li>Amount of frequency in use</li><li>20 mhz, 40 mhz, 80 mhz, 160 mhz, etc. Channel 6 is 2.4 ghz range includes 2.437 ghz maybe more spectrum Channel 44 is 5 ghz range inclues 5.220 ghz and maybe more range</li></ul><p>802.11 Spectrum For:</p><ul><li>Frequency range increases as well as bandwidth</li></ul><table tabindex="0"><thead><tr><th>Frequency</th><th>Bandwidth</th></tr></thead><tbody><tr><td>2.4 GHz</td><td>20 MHz</td></tr><tr><td>5 GHz</td><td>20, 40, 80, 160 MHz</td></tr><tr><td>6 GHz</td><td>20, 40, 80, 160, 320 MHz</td></tr></tbody></table><p>Frequency bands are radio waves that carry data, this is how wireless data is transfered between devices.</p><table tabindex="0"><thead><tr><th>Frequency Band</th><th>Description</th></tr></thead><tbody><tr><td>2.4 GHz</td><td>Most common with other devices (fridge, microwave, smart devices), potentialy more interference, slower speed longer range</td></tr><tr><td>5 GHz</td><td>Less common, minimal interference, 25 non overlapping channels, faster speed shorter range. Difficulty penetrating solid objects like walls</td></tr></tbody></table><p>Wireless channels - fine tune and alter frequency</p><p>WiFi</p><ul><li>connect devices to internet</li><li>Range 30 - 91 meters (100 - 300 feet)</li></ul><p>Bluetooth</p><ul><li>connect devices to each other and exchange data</li><li>slower transfer rate and shorter range vs wifi</li><li>less power, longer battery life</li><li>less vulnerable to interference</li><li>uses FHSS (Frequency Hopping Spread Spectrum) less likely to get interference from other 2.4 GHz devices unlike wiFi</li><li>simpler to use/ often no password required</li><li>headsets, speakers, keyboards/mice</li><li>uses the 2.4 GHz range</li><li>Unlicensed ISM (Industrial, Scientific and Medical) band</li><li>Same as 802.11 Short-range</li><li>mos consumer devices operate to about 10 meters (30 feet)</li></ul><p>RFID (Radio-frequency identification)</p><ul><li>access badges</li><li>inventory/assembly line tracking</li><li>pet/animal identification</li><li>anything that needs to be tracked Radar Technology</li><li>radio enery transmitted to the tag</li><li>RF powers the tag (no battery, not powered alone), ID is transmitted back</li><li>Bidirectional communication</li><li>Some tag formats can be active/powered (some do have batteries) and can be tracked a longer distance away NFC (Near Field Communication)</li><li>two-way communication</li><li>builds 0n RFID, which is mostly one-way payment systmes</li><li>major credit cards, online wallets boostrap for other wireless</li><li>NFC helps with Bluetooth pairing Access token, identity &#39;card&#39;</li><li>short range with encryption support</li></ul>',20)])])}const p=t(r,[["render",o]]);export{m as __pageData,p as default};
